import type { SupplierPerformance } from '../types';
const Metric=({label,value,detail}:{label:string;value:string;detail:string})=><article className="rounded-xl border border-slate-200 bg-white p-4 dark:border-slate-700 dark:bg-slate-900"><p className="text-xs font-semibold uppercase tracking-wide text-slate-400">{label}</p><p className="mt-2 text-2xl font-bold tabular-nums text-slate-900 dark:text-white">{value}</p><p className="mt-1 text-xs text-slate-500 dark:text-slate-400">{detail}</p></article>;
export const PerformanceCards=({data}:{data:SupplierPerformance})=><div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-4"><Metric label="Delivery" value={`${Number(data.delivery_performance_pct).toFixed(1)}%`} detail={`${data.on_time_orders} of ${data.measured_deliveries} measured orders`}/><Metric label="Completion" value={`${Number(data.order_completion_pct).toFixed(1)}%`} detail={`${data.completed_orders} of ${data.eligible_orders} eligible orders`}/><Metric label="Quality" value={data.product_quality_score===null?'Not rated':`${Number(data.product_quality_score).toFixed(1)} / 5`} detail="Latest reviewed product quality"/><Metric label="Return Rate" value={`${Number(data.return_rate_pct).toFixed(1)}%`} detail="Returned or damaged received stock"/><Metric label="Average Lead Time" value={`${Number(data.average_lead_time_days).toFixed(1)} days`} detail="Order to first goods receipt"/><Metric label="Procurement Value" value={`${data.currency} ${Number(data.procurement_value).toLocaleString()}`} detail="Eligible purchase orders"/><Metric label="Overall Rating" value={data.overall_rating===null?'Not rated':`${Number(data.overall_rating).toFixed(2)} / 5`} detail="Latest weighted review"/></div>;
